import { useState, useEffect } from "react";
import jsPDF from "jspdf";
import { GlobalStyle } from "./globalStyles";
import {
  RateUs,
  DownloadButton,
  DownloadButton2,
  CameraImage1,
  CameraImage2,
  BetaLabel,
  DownloadText,
  ShowContainerImages,
  Movingimage,
  ShowScreenShotImagesO,
} from "./index.styled";

import logo from "./Images/logo.svg";
import starIcon from "./Images/star.svg";
import editingPic from "./Images/editing.svg";
import cameraIcon from "./Images/cameraIcon.svg";
import tickIcon from "./Images/tickButton.svg";

function App() {
  const [images, setImages] = useState([]);
  const [totalFrames, setTotalFrames] = useState(0);
  let imagel = [];
  const [processState, setProcessState] = useState("loading");
  const [loading, setLoading] = useState(true);
  const [isDownloaded, setIsDownloaded] = useState(false);
  let imageArray;

  const downloadPdf = (finalImagetoDownload) => {
    const longImage = new Image();
    longImage.src = finalImagetoDownload;
    let width = 570;
    let height = 850;
    let fixed = 0.5;
    let pdfWidth = width;
    let pdfHeight = height;
    let ori = "p";
    longImage.onload = function () {
      if (longImage.width * fixed > pdfWidth - 40) {
        ori = "l";
        pdfWidth = height;
        pdfHeight = width;
        fixed = (pdfWidth - 40) / longImage.width;
      }
      let canvasForImg = document.createElement("canvas");
      const pdf = new jsPDF(ori, "pt");
      for (let page = 0; page < longImage.height; ) {
        if (page !== 0) {
          pdf.addPage();
        }
        const width = canvasForImg.getContext("2d");
        canvasForImg.width = longImage.width;
        canvasForImg.height = (pdfHeight - 20) / fixed;
        width.rect(0, 0, canvasForImg.width, canvasForImg.height);
        width.fillStyle = "white";
        width.fill();
        width.drawImage(
          longImage,
          0,
          page,
          longImage.width,
          longImage.height - page,
          0,
          0,
          longImage.width,
          longImage.height - page
        );
        const imgdata = canvasForImg.toDataURL("image/jpeg", 1);
        pdf.addImage(
          imgdata,
          "JPEG",
          10,
          10,
          canvasForImg.width * fixed,
          canvasForImg.height * fixed
        );
        page += canvasForImg.height;
      }
      setIsDownloaded(true);
      pdf.save("finalPdf.pdf");

      setTimeout(() => {
        imageArray = [];
        setImages([]);
        setLoading(true);
        setIsDownloaded(false);
      }, 1000);
    };
  };

  const handleStartButtonClick = () => {
    window.chrome.tabs.query(
      {
        active: true,
        currentWindow: true,
      },
      function (tabs) {
        var activeTab = tabs[0];
        window.chrome.tabs.sendMessage(
          activeTab.id,
          {
            message: "start",
            websiteUrl: activeTab.url,
          },
          function (response) {}
        );
      }
    );
    window.close();
  };

  const handleSendButtonClick = () => {
    setLoading(false);
    imageArray = [];
    setImages([]);
    window.chrome.tabs.query(
      {
        active: true,
        currentWindow: true,
      },
      function (tabs) {
        var activeTab = tabs[0];
        window.chrome.tabs.sendMessage(
          activeTab.id,
          {
            message: "INITIATE_SCREENSHOT",
            websiteUrl: activeTab.url,
          },
          function (response) {}
        );
      }
    );
  };

  const generateLink = () => {
    const extensionId = window.chrome.runtime.id;

    const rateUsUrl = `https://chrome.google.com/webstore/detail/${extensionId}/reviews`;
    window.open(rateUsUrl, "_blank");
  };

  useEffect(() => {
    window.chrome.runtime.onMessage.addListener(function (
      request,
      sender,
      sendResponse
    ) {
      switch (request.message) {
        case "pdfData":
          downloadPdf(request.imageData);
        case "SCROLLED":
          let { totalframes, img, framesCovered, lastFrame } = request;

          let interval = Math.ceil(totalframes / 5);

          if (totalFrames != 0 && totalFrames != totalframes) {
            interval = Math.ceil(totalframes / (5 - images.length));
          }
          if (interval == 1 || framesCovered % interval == 0 || lastFrame) {
            imageArray.push(img);
            setImages([...imageArray]);
            setTotalFrames(totalframes);
          }
          break;
      }
    });
  }, []);

  return (
    <>
      <GlobalStyle />

      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
        }}
      >
        <img
          src={logo}
          alt="Webpage to pdf Converter"
          style={{
            width: "207px",
            height: "22px",
            marginTop: "18px",
            marginLeft: "18px",
          }}
        />

        <RateUs onClick={generateLink}>
          <img src={starIcon} alt="Rate us" />
          Rate us
        </RateUs>
      </div>

      {loading ? (
        <>
          <DownloadButton onClick={handleSendButtonClick}>
            <CameraImage1 src={cameraIcon} alt="Camera Icon" />
            Webpage to pdf
          </DownloadButton>

          <DownloadButton2 onClick={handleStartButtonClick}>
            <CameraImage2 src={editingPic} alt="Camera Icon" />
            Webpage to pdf / edit <BetaLabel>Beta</BetaLabel>
          </DownloadButton2>
        </>
      ) : (
        <>
          <ShowContainerImages>
            {
              (imagel = images.map((image, i) => {
                if (processState == "loading") {
                  return (
                    <ShowScreenShotImagesO
                      src={image}
                      key={i}
                      frames={totalFrames <= 5 ? totalFrames : 5}
                    />
                  );
                } else {
                  return (
                    <>
                      <ShowScreenShotImagesO
                        src={image}
                        key={i}
                        frames={images.length}
                      />
                    </>
                  );
                }
              }))
            }

            <Movingimage
              src={cameraIcon}
              style={{ visibility: images.length < 5 ? "visible" : "hidden" }}
            />
          </ShowContainerImages>
        </>
      )}
      {isDownloaded && (
        <DownloadText>
          <img src={tickIcon} alt="Downloaded" />
          Downloaded
        </DownloadText>
      )}
    </>
  );
}

export default App;
